import{o as a,c as o,aw as s}from"./chunks/framework.Dq2onT5h.js";const n=JSON.parse('{"title":"Using Local DA","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"Using Local DA | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"guides/da/local-da.md","filePath":"guides/da/local-da.md","lastUpdated":1765840739000}'),e={name:"guides/da/local-da.md"},l=Object.assign(e,{setup:n=>(n,e)=>(a(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="using-local-da" tabindex="-1">Using Local DA <a class="header-anchor" href="#using-local-da" aria-label="Permalink to &quot;Using Local DA&quot;">​</a></h1><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction {#introduction}&quot;">​</a></h2><p>This tutorial serves as a comprehensive guide for using the <a href="./../../../tools/local-da">local-da</a> with your chain.</p><p>Before proceeding, ensure that you have completed the <a href="./../gm-world">build a chain</a> tutorial, which covers setting-up, building and running your chain.</p><h2 id="setting-up-a-local-da-network" tabindex="-1">Setting Up a Local DA Network <a class="header-anchor" href="#setting-up-a-local-da-network" aria-label="Permalink to &quot;Setting Up a Local DA Network&quot;">​</a></h2><p>To set up a local DA network node on your machine, run the following script to install and start the local DA node:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">go</span><span style="color:#BFF3C2;"> install</span><span style="color:#BFF3C2;"> github.com/evstack/ev-node/tools/local-da@latest</span></span></code></pre></div><p>This script will build and run the node, which will then listen on port <code>7980</code>.</p><h2 id="configuring-your-chain-to-connect-to-the-local-da-network" tabindex="-1">Configuring your chain to connect to the local DA network <a class="header-anchor" href="#configuring-your-chain-to-connect-to-the-local-da-network" aria-label="Permalink to &quot;Configuring your chain to connect to the local DA network&quot;">​</a></h2><p>To connect your chain to the local DA network, you need to pass the <code>--evnode.da.address</code> flag with the local DA node address.</p><h2 id="run-your-chain" tabindex="-1">Run your chain <a class="header-anchor" href="#run-your-chain" aria-label="Permalink to &quot;Run your chain&quot;">​</a></h2><p>Start your chain node with the following command, ensuring to include the DA address flag:</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-rNlaY" id="tab-fGzucl1" checked><label data-title="Quick Start" for="tab-fGzucl1">Quick Start</label><input type="radio" name="group-rNlaY" id="tab-54RUdv4"><label data-title="gm-world Chain" for="tab-54RUdv4">gm-world Chain</label></div><div class="blocks"><div class="language-sh active"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">testapp</span><span style="color:#BFF3C2;"> start</span><span style="color:#FFECB6;"> --evnode.da.address</span><span style="color:#BFF3C2;"> http://localhost:7980</span></span></code></pre></div><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">testapp</span><span style="color:#BFF3C2;"> start</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">    --evnode.node.aggregator</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">    --evnode.da.address</span><span style="color:#BFF3C2;"> http://localhost:7980</span><span style="color:#FFECB6;"> \\</span></span></code></pre></div></div></div><p>You should see the following log message indicating that your chain is connected to the local DA network:</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">11:07AM</span><span style="color:#BFF3C2;"> INF</span><span style="color:#BFF3C2;"> NewLocalDA:</span><span style="color:#BFF3C2;"> initialized</span><span style="color:#BFF3C2;"> LocalDA</span><span style="color:#BFF3C2;"> module=local-da</span></span>\n<span class="line"><span style="color:#94EEFF;">11:07AM</span><span style="color:#BFF3C2;"> INF</span><span style="color:#BFF3C2;"> Listening</span><span style="color:#BFF3C2;"> on</span><span style="color:#BFF3C2;"> host=localhost</span><span style="color:#BFF3C2;"> maxBlobSize=</span><span style="color:#FFECB6;">1974272</span><span style="color:#BFF3C2;"> module=da</span><span style="color:#BFF3C2;"> port=</span><span style="color:#FFECB6;">7980</span></span>\n<span class="line"><span style="color:#94EEFF;">11:07AM</span><span style="color:#BFF3C2;"> INF</span><span style="color:#BFF3C2;"> server</span><span style="color:#BFF3C2;"> started</span><span style="color:#BFF3C2;"> listening</span><span style="color:#BFF3C2;"> on=localhost:7980</span><span style="color:#BFF3C2;"> module=da</span></span></code></pre></div><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>By following these steps, you will set up a local DA network node and configure your chain to post data to it. This setup is useful for testing and development in a controlled environment. You can find more information in the <a href="./../../../tools/local-da/README">local-da README</a></p>',17)])]))});export{n as __pageData,l as default};
